  dealer!: Dealer;
  gameId!: string;
  player!: Player;
  players!: Player[];
  playersLeft!: Player[];
  playersRight!: Player[];
  shoe!: Shoe;
  state!: GameState;

  constructor(gameSettings: Partial<GameSettings> = SETTINGS_DEFAULTS) {
    super();

    settings = defaultSettings();
    this.updateSettings(gameSettings);
    this.betAmount = settings.minimumBet;
    this.spotCount = 1;

    if (settings.disableEvents) {
      EventEmitter.disableEvents = true;
    }

    this.setupState();
  }

  get focusedHand(): Hand {
    return this.player.getHand(this.state.focusedHandIndex);
  }

  get settings(): GameSettings {
    return settings;
  }

  updateSettings(gameSettings: Partial<GameSettings>): GameSettings {
    return Utils.merge(settings, gameSettings);
  }

  setupState(): void {
    // We assign a random ID to each game so that we can link hand results with
    // wrong moves in the database.
    this.gameId = Utils.randomId();

    this.shoe = this.chainEmitChange(new Shoe());
    this.dealer = this.chainEmitChange(
      new Dealer({
        handsMax: settings.maxHandsAllowed,
        debug: settings.debug,
        strategy: PlayerStrategy.Dealer,
      }),
    );

    this.players = Array.from(
      { length: settings.playerCount },
      (_item, index) =>
        this.chainEmitChange(
          new Player({
            handsMax: settings.maxHandsAllowed,
            balance: settings.playerBankroll,
            blackjackPayout: settings.blackjackPayout,
            debug: settings.debug,
            // TODO: Make this configurable for each player.
            strategy:
              settings.playerStrategyOverride[index + 1] ??
              (index === settings.playerTablePosition - 1
                ? PlayerStrategy.UserInput
                : PlayerStrategy.BasicStrategy),
          }),
        ),
    );

    // We reverse the players array for convenience since reverse iteration in
    // JS is difficult.
    this.players.reverse();

    const reversedTablePosition =
      this.players.length - settings.playerTablePosition + 1;

    this.player = this.players[reversedTablePosition - 1];
    this.playersLeft = this.players.slice(reversedTablePosition);
    this.playersRight = this.players.slice(0, reversedTablePosition - 1);

    this.player.on(Event.HandWinner, (hand, winner) => {
      this.emit(Event.CreateRecord, 'hand-result', {
        createdAt: Date.now(),
        gameId: this.gameId,
        dealerHand: this.dealer.firstHand.serialize({ showHidden: true }),
        playerHand: hand.serialize(),
        winner,
      });
    });

    this._state = {
      focusedHandIndex: 0,
      playCorrection: '',
      sessionMovesCorrect: 0,
      sessionMovesTotal: 0,
      step: GameStep.Start,
    };

    const hasKey = <T extends SimpleObject>(
      obj: T,
      k: string | number | symbol,
    ): k is keyof T => k in obj;

    this.state = settings.disableEvents
      ? this._state
      : new Proxy(this._state, {
          set: (target, key, value: unknown) => {
            if (hasKey(target, key)) {
              Reflect.set(target, key, value);
            }

            if (hasAttributes(value)) {
              this.emit(Event.Change, String(key), value.attributes());
            } else if (typeof value === 'string' || typeof value === 'number') {
              this.emit(Event.Change, String(key), value);
            }

            return true;
          },
        });
  }

  resetState(): void {
    this.setupState();
    this.emit(Event.ResetState);
  }

  allPlayerHandsBusted(): boolean {
    return this.players.every((player) =>
      player.hands.every((hand) => hand.busted || hand.blackjack),
    );
  }

  chainEmitChange<T extends EventEmitter<EventMap>>(object: T): T {
    object.on(Event.Change, (name, value) =>
      this.emit(Event.Change, name, value),
    );
    return object;
  }

  getCheckerResult(
    hiLoResult: CheckDeviationResult | undefined,
    basicStrategyResult: CheckResult,
    input: Move,
  ): CheckDeviationResult | CheckResult {
    // A basic strategy split takes priority over any deviation.
    // For example pair 6s vs 2 should be a split even though I18 says to hit.
    if (input === Move.Split && basicStrategyResult.result) {
      return basicStrategyResult;
    }

    // A basic strategy surrender takes priority over non-Fab4 deviations.
    // For example 15v10 should be a surrender even though I18 says to hit.
    if (input === Move.Surrender && basicStrategyResult.result) {
      return hiLoResult?.deviation.fab4 === true
        ? hiLoResult
        : basicStrategyResult;
    }

    return hiLoResult || basicStrategyResult;
  }

  validateInput(input: Move, hand: Hand): void {
    const hiLoResult = HiLoDeviationChecker.check(this, hand, input);
    const basicStrategyResult = BasicStrategyChecker.check(this, hand, input);

    const checkerResult = this.getCheckerResult(
      hiLoResult,
      basicStrategyResult,
      input,
    );

    if (checkerResult.hint != null) {
      this.state.playCorrection = checkerResult.hint;
    } else {
      this.state.sessionMovesCorrect += 1;
    }

    this.state.sessionMovesTotal += 1;

    this.emit(Event.CreateRecord, 'move', {
      createdAt: Date.now(),
      gameId: this.gameId,
      dealerHand: this.dealer.firstHand.serialize({ showHidden: true }),
      playerHand: this.focusedHand.serialize(),
      move: input,
      correction: typeof checkerResult === 'object' ? checkerResult.code : null,
    });
  }

  isValidPlayHandsInput(input: Move | undefined): input is Move {
    if (this.player.isNPC) {
      return true;
    }

    if (
      input === undefined ||
      ![Move.Hit, Move.Stand, Move.Double, Move.Split, Move.Surrender].includes(
        input,
      )
    ) {
      return false;
    }

    if (input === Move.Surrender && !this.focusedHand.allowSurrender) {
      return false;
    }

    if (input === Move.Split && !this.focusedHand.allowSplit) {
      return false;
    }

    if (input === Move.Double && !this.focusedHand.allowDouble) {
      return false;
    }

    return true;
  }

  isValidInsuranceInput(input: Move | undefined): input is Move {
    if (this.player.isNPC) {
      return true;
    }

    return (
      input !== undefined &&
      [Move.AskInsurance, Move.NoInsurance].includes(input)
    );
  }

  step(input?: Move): GameStep {
    let step: GameStep = this.state.step;

    try {
      switch (step) {
        case GameStep.Start:
          step = this.dealInitialCards();
          break;

        case GameStep.WaitingForInsuranceInput:
          if (!this.isValidInsuranceInput(input)) {
            break;
          }

          if (
            settings.checkDeviations === true ||
            settings.mode === GameMode.Deviations
          ) {
            this.validateInput(input, this.focusedHand);
          }

          this.askInsurance(input, this.player, ...this.playersLeft);

          if (this.dealer.holeCard.value === 10) {
            // Flip hole card before payout so the dealer's blackjack state
            // is set when setHandWinner emits the change event.
            this.dealer.firstHand.incrementTotalsForCard(this.dealer.cards[0]);
            this.dealer.cards[0].flip();
            this.payoutInsurance(input);
            step = GameStep.WaitingForNewGameInput;
          } else {
            this.payoutInsurance(input);
            step = GameStep.PlayHandsRight;
          }

          break;

        case GameStep.PlayHandsRight:
          this.playNPCHands(...this.playersRight);
          step = this.setblackjackWinner(this.player, this.focusedHand)
            ? GameStep.PlayHandsLeft
            : GameStep.WaitingForPlayInput;
          break;

        case GameStep.WaitingForPlayInput:
          if (!this.isValidPlayHandsInput(input)) {
            break;
          }

          if (this.player.isUser) {
            step = this.playUserHands(input);
          } else {
            this.playNPCHands(this.player);
            step = GameStep.PlayHandsLeft;
          }

          break;

        case GameStep.PlayHandsLeft:
          this.playNPCHands(...this.playersLeft);
          this.playDealer();
          step = GameStep.WaitingForNewGameInput;
          break;

        case GameStep.WaitingForNewGameInput:
          if (this.player.isUser && input === undefined) {
            break;
          }
          this.removeCards();
          step = GameStep.Start;
      }
    } catch (error) {
      if (error instanceof OutOfCardsError) {
        this.pushAllPlayersHands();
        step = GameStep.WaitingForNewGameInput;
      } else {
        throw error;
      }
    }

    this.state.step = step;

    return step;
  }

  run(betAmount: number, spotCount: number): void {
    this.betAmount = betAmount;
    this.spotCount = spotCount;

    let nextStep: GameStep = this.state.step;

    do {
      nextStep = this.step();
    } while (nextStep !== GameStep.Start);
  }

  dealInitialCards(): GameStep {
    if (settings.debug) {
      console.log(`> Starting new hand (player ID ${this.player.id})`);
      console.log('Shoe:', this.shoe.serialize());
    }

    for (const player of this.players) {
      // Clears the result from the previous iteration. Otherwise this object
      // will grow indefinitely over subsequent `step()` calls.
      player.handWinner = new Map();

      for (
        let i = 0;
        i < (player === this.player ? this.spotCount : 1);
        i += 1
      ) {
        // TODO: Make NPCs bet more realistically than minimum bet.
        const hand = player.addHand(
          player === this.player ? this.betAmount : settings.minimumBet,
        );

        // Draw card for each player face up (upcard).
        player.takeCard(this.shoe.drawCard(), { hand });
      }
    }

    // Draw card for dealer face up.
    this.dealer.addHand();
    this.dealer.takeCard(this.shoe.drawCard());

    // Draw card for each player face up again (upcard).
    for (const player of this.players) {
      player.eachHand((hand) => {
        player.takeCard(this.shoe.drawCard(), { hand });
      });
    }

    // Draw card for dealer face down (hole card).
    this.dealer.takeCard(this.shoe.drawCard({ showingFace: false }), {
      prepend: true,
    });

    // Dealer peeks at the hole card if the upcard is 10 to check blackjack.
    if (this.dealer.upcard.value === 10 && this.dealer.holeCard.value === 11) {
      this.dealer.firstHand.incrementTotalsForCard(this.dealer.cards[0]);
      this.dealer.cards[0].flip();

      for (const player of this.players) {
        player.eachHand((hand) => {
          player.setHandWinner({
            winner: hand.blackjack ? HandWinner.Push : HandWinner.Dealer,
            hand,
          });
        });
      }

      return GameStep.WaitingForNewGameInput;
    }

    // Dealer peeks at the hole card if the upcard is ace to ask insurance.
    if (this.dealer.upcard.value === 11) {
      this.askInsurance(null, ...this.playersRight);

      if (!settings.autoDeclineInsurance) {
        return GameStep.WaitingForInsuranceInput;
      }
    }

    return GameStep.PlayHandsRight;
  }

  askInsurance(userInput: Move | null | undefined, ...players: Player[]): void {
    for (const player of players) {
      player.eachHand((hand) => {
        const input =
          player.isUser && userInput != null
            ? userInput
            : player.getNPCInput(this, hand);

        // TODO: Make insurance amount configurable. Currently uses half the bet
        // size as insurance to recover full bet amount.
        const amount =
          player === this.player ? this.betAmount : settings.minimumBet;

        if (input === Move.AskInsurance) {
          player.useChips(amount / 2, { hand });
        }
      });
    }
  }

  payoutInsurance(userInput: Move | undefined): void {
    if (this.dealer.holeCard?.value !== 10) {
      return;
    }

    for (const player of this.players) {
      player.eachHand((hand) => {
        player.setHandWinner({
          winner: hand.blackjack ? HandWinner.Push : HandWinner.Dealer,
          hand,
        });

        // TODO: Store this in state so we don't have to check it again.
        const input = player.isUser
          ? userInput
          : player.getNPCInput(this, hand);

        if (input === Move.AskInsurance) {
          // Insurance costs half the bet and pays 2:1. Return the stake plus
          // winnings: (bet / 2) * 3 = bet * 1.5.
          const bet =
            player === this.player ? this.betAmount : settings.minimumBet;
          player.addChips(bet * 1.5);
        }
      });
    }
  }

  setblackjackWinner(player: Player, hand: Hand): boolean {
    if (this.dealer.blackjack && hand.blackjack) {
      player.setHandWinner({ winner: HandWinner.Push, hand });
      return true;
    } else if (this.dealer.blackjack) {
      player.setHandWinner({ winner: HandWinner.Dealer, hand });
      return true;
    } else if (hand.blackjack) {
      player.setHandWinner({ winner: HandWinner.Player, hand });
      return true;
    }

    return false;
  }

  stepHand(
    player: Player,
    hand: Hand,
    betAmount: number,
    input: Move,
  ): boolean {
    if (this.setblackjackWinner(player, hand)) {
      return true;
    }

    if (hand.fromAceSplit && !hand.allowSplit) {
      return true;
    }

    if (hand.cardTotal <= 21) {
      if (!player.isNPC) {
        this.validateInput(input, hand);
      }

      if (input === Move.Hit) {
        player.takeCard(this.shoe.drawCard(), { hand });
      }

      if (input === Move.Stand) {
        return true;
      }

      if (input === Move.Double) {
        player.useChips(betAmount, { hand });
        player.takeCard(this.shoe.drawCard(), { hand });
      }

      if (input === Move.Split && hand.allowSplit) {
        const newHandCard = hand.removeCard();
        const newHand = player.addHand(betAmount, [newHandCard]);

        hand.splitCount += 1;
        newHand.splitCount = hand.splitCount;

        player.takeCard(this.shoe.drawCard(), { hand });
        player.takeCard(this.shoe.drawCard(), { hand: newHand });

        if (hand.hasAces) {
          return true;
        }
      }

      if (input === Move.Surrender) {
        player.setHandWinner({
          winner: HandWinner.Dealer,
          hand,
          surrender: true,
        });

        return true;
      }
    }

    if (hand.busted) {
      if (settings.debug) {
        console.log(`Busted ${player.id} ${hand.cardTotal}`);
      }

      player.setHandWinner({ winner: HandWinner.Dealer, hand });

      return true;
    }

    if (input === Move.Double) {
      return true;
    }

    if (hand.cardTotal === 21) {
      return true;
    }

    return false;
  }

  playNPCHands(...players: Player[]): void {
    for (const player of players) {
      player.eachHand((hand) => {
        let handFinished = false;

        while (!handFinished) {
          handFinished = this.stepHand(
            player,
            hand,
            player === this.player ? this.betAmount : settings.minimumBet,
            player.getNPCInput(this, hand),
          );
        }
      });
    }
  }

  playUserHands(input: Move): GameStep {
    const handFinished = this.stepHand(
      this.player,
      this.focusedHand,
      this.betAmount,
      input,
    );

    if (handFinished) {
      if (this.state.focusedHandIndex < this.player.handsCount - 1) {
        this.state.focusedHandIndex += 1;
      } else {
        return GameStep.PlayHandsLeft;
      }
    }

    // If aces were split, we may have to advance focus multiple times.
    while (
      this.state.focusedHandIndex < this.player.handsCount - 1 &&
      this.focusedHand.finished
    ) {
      this.state.focusedHandIndex += 1;
    }

    return this.focusedHand.finished
      ? GameStep.PlayHandsLeft
      : GameStep.WaitingForPlayInput;
  }

  playDealer(): void {
    this.dealer.firstHand.incrementTotalsForCard(this.dealer.cards[0]);
    this.dealer.cards[0].flip();

    // Dealer draws cards until they reach 17. However, if all player hands have
    // busted, this step is skipped.
    // TODO: Move this into `getNPCInput()` for `PlayerStrategy.DEALER`.
    if (!this.allPlayerHandsBusted()) {
      while (this.dealer.cardTotal <= 17 && !this.dealer.blackjack) {
        if (
          this.dealer.cardTotal === 17 &&
          (this.dealer.isHard || !settings.hitSoft17)
        ) {
          break;
        }

        this.dealer.takeCard(this.shoe.drawCard());
      }
    }

    for (const player of this.players) {
      player.eachHand((hand) => {
        if (player.handWinner.get(hand.id) !== undefined) {
          return;
        }

        if (this.dealer.busted) {
          player.setHandWinner({ winner: HandWinner.Player, hand });
        } else if (this.dealer.cardTotal > hand.cardTotal) {
          player.setHandWinner({ winner: HandWinner.Dealer, hand });
        } else if (hand.cardTotal > this.dealer.cardTotal) {
          player.setHandWinner({ winner: HandWinner.Player, hand });
        } else {
          player.setHandWinner({ winner: HandWinner.Push, hand });
        }
      });
    }
  }

  pushAllPlayersHands(): void {
    for (const player of this.players) {
      player.eachHand((hand) => {
        player.setHandWinner({ winner: HandWinner.Push, hand });
      });
    }
  }

  removeCards(): void {
    this.state.playCorrection = '';
    this.state.focusedHandIndex = 0;

    for (const player of this.players) {
      player.removeCards();
    }

    this.dealer.removeCards();

    if (this.shoe.needsReset) {
      if (settings.debug) {
        console.log('Cut card reached');
      }
      this.shoe.resetCards();
      this.emit(Event.Shuffle);
    }

    if (settings.debug) {
      console.log('End of hand', this.shoe.serialize());
      console.log();
    }
  }
}

import Utils from './utils';
import Deck from './deck';
import Card from './card';
import GameObject from './game-object';
import BasicStrategyChecker from './basic-strategy-checker';
import ExtendableError from './extendable-error';
import {
  illustrious18Deviations,
  fab4Deviations,
} from './hi-lo-deviation-checker';
import { settings } from './game';
import type { ShoeAttributes } from './event-types';
import {
  Rank,
  ChartType,
  cardValueToRank,
  rankToString,
  GameMode,
  Move,
  Deviation,
} from './types';

export class OutOfCardsError extends ExtendableError {}

export default class Shoe extends GameObject {
  entityName = 'shoe';

  cards!: Card[];
  currentCardIndex!: number;
  hiLoRunningCount!: number;

  constructor() {
    super();

    this.setCards(this._setupCards());
    this.shuffle();
  }

  setCards(cards: Card[]): void {
    this.hiLoRunningCount = 0;
    this.currentCardIndex = cards.length - 1;

    for (const card of cards) {
      this.hiLoRunningCount -= card.hiLoValue;
      card.showingFace = false;
    }

    this.cards = cards;
    this.emitChange();
  }

  resetCards(): void {
    this.hiLoRunningCount = 0;
    this.currentCardIndex = this.cards.length - 1;
    this.shuffle();
  }

  shuffle(): void {
    Utils.arrayShuffle(this.cards);

    if (settings.mode === GameMode.Pairs) {
      this._setupPairsMode();
    }

    if (settings.mode === GameMode.Uncommon) {
      this._setupUncommonMode();
    }

    if (settings.mode === GameMode.Deviations) {
      this._setupDeviationsMode();
    }

    if (settings.debug) {
      console.log('Shoe shuffled');
    }
  }

  drawCard({ showingFace = true } = {}): Card {
    // This is an edge case that will rarely be reached during game mode. It can
    // happen if the pen is sufficiently deep and player count is large enough.
    // It does occur frequently in simulation mode where large amounts of hands
    // are played. Casinos seem to deal with it in varying ways. We handle it by
    // pushing all player hands and reshuffling.
    if (this.currentCardIndex < 0) {
      throw new OutOfCardsError();
    }

    const card = this.cards[this.currentCardIndex];

    this.currentCardIndex -= 1;

    card.showingFace = showingFace;

    if (showingFace) {
      this.hiLoRunningCount += card.hiLoValue;
    }

    this.emitChange();

    return card;
  }

  remainingCards(): Card[] {
    return this.cards.slice(0, this.currentCardIndex + 1);
  }

  attributes(): ShoeAttributes {
    return Utils.copy({
      penetration: Utils.round(this.penetration, 2),
      hiLoRunningCount: this.hiLoRunningCount,
      hiLoTrueCount: Utils.round(this.hiLoTrueCount, 2),
      cards: this.remainingCards().map((card) => card.attributes()),
    });
  }

  serialize(): string {
    return (
      `(${this.cardCount} card${this.cardCount > 1 ? 's' : ''}): ` +
      this.remainingCards()
        .map((card) => rankToString(card.rank))
        .reverse()
        .join(' ')
    );
  }

  get cardCount(): number {
    return this.currentCardIndex + 1;
  }

  get maxCards(): number {
    return settings.deckCount * 52;
  }

  get needsReset(): boolean {
    if (settings.mode !== GameMode.Default) {
      return true;
    }

    return this.cardCount / this.maxCards < 1 - settings.penetration;
  }

  get cardsRemainingRatio(): number {
    return this.cardCount / this.maxCards;
  }

  get penetration(): number {
    return (1 - this.cardsRemainingRatio) * 100;
  }

  get decksRemaining(): number {
    return this.cardsRemainingRatio * settings.deckCount;
  }

  get hiLoTrueCount(): number {
    return this.hiLoRunningCount / this.decksRemaining;
  }

  setupDeviationScenario(
    playerTotal: number,
    dealerTotal: number,
    deviation: Deviation,
  ): void {
    let total =
      deviation.correctMove === Move.AskInsurance
        ? Utils.random(2, 20)
        : playerTotal;

    const pair = deviation.correctMove === Move.Split;

    // TODO: Make the splits format just equal the player total.
    if (pair) {
      total = total / 2;
    }

    const [rank1, rank2] = this._playerTotalToTwoCardRank(
      total,
      pair ? ChartType.Splits : ChartType.Hard,
    );

    this._moveCardsToFront(rank1, rank2, dealerTotal);

    // Include all face up cards in the count from the opening hand.
    const i1 = this.cards[this.cards.length - 1].hiLoValue;
    const i2 = this.cards[this.cards.length - 2].hiLoValue;
    const i3 = this.cards[this.cards.length - 3].hiLoValue;

    // We artificially set the running count so that the true count works out to
    // what is required to act on the current deviation. We use the formula
    // `true_count = running_count / decks_remaining`. We are careful to
    // subtract the next 3 cards from the running count since they are about to
    // be drawn by the dealer.
    let runningCount =
      deviation.index[1] *
        (((this.maxCards - 3) * settings.deckCount) / this.maxCards) -
      i1 -
      i2 -
      i3;

    const lt = deviation.index[0][0] === '<';

    // Since we forced the true count to a nice number, the running count will
    // be a decimal. We round it up or down depending on whether the deviation
    // acts on indices going further negative or positive.
    runningCount = Math[lt ? 'floor' : 'ceil'](runningCount);

    // Force the true count one point less for the '<' comparison since it
    // is an exclusive equality check.
    if (deviation.index[0].includes('<')) {
      runningCount -= this.decksRemaining;
    }

    this.hiLoRunningCount = runningCount;
  }

  _setupCards(): Card[] {
    const decks = [];
    for (let i = 0; i < settings.deckCount; i += 1) {
      decks.push(new Deck(this));
    }

    let cards: Card[] = [];
    while (decks.length > 0) {
      const deck = decks.pop();
      if (deck) {
        cards = cards.concat(...deck.cards);
      }
    }

    return cards;
  }

  _moveCardsToFront(
    playerRank1: Rank,
    playerRank2: Rank,
    dealerUpcard?: number,
  ): void {
    // Move the first two cards to the 0th and 2nd spot so they are dealt to the
    // player at the start of the game.
    Utils.arrayMove(
      this.cards,
      this.cards.findIndex((card) => card.rank === playerRank1),
      this.cards.length - 1,
    );

    if (dealerUpcard !== undefined) {
      Utils.arrayMove(
        this.cards,
        this.cards.findIndex((card) => card.value === dealerUpcard),
        this.cards.length - 1 - 1,
      );
    }

    Utils.arrayMove(
      this.cards,
      this.cards.findIndex((card) => card.rank === playerRank2),
      this.cards.length - 1 - 2,
    );
  }

  _playerTotalToTwoCardRank(total: number, chartType: ChartType): [Rank, Rank] {
    const [rank1, rank2] = this._playerTotalToTwoCardValues(total, chartType);
    return [cardValueToRank(rank1), cardValueToRank(rank2)];
  }

  _playerTotalToTwoCardValues(
    total: number,
    chartType: ChartType,
  ): [number, number] {
    switch (chartType) {
      case ChartType.Hard: {
        const value = total > 11 ? 10 : 2;
        return [value, total - value];
      }

      case ChartType.Soft:
        return [11, total - 11];

      default:
      case ChartType.Splits:
        return [total, total];
    }
  }

  _setupPairsMode(): void {
    const rank = Utils.randomRank();
    this._moveCardsToFront(rank, rank);
  }

  _setupUncommonMode(): void {
    const [chartType, chart] = Utils.arraySample(
      Array.from(BasicStrategyChecker.uncommonHands(settings).entries()),
    );

    const [playerTotal, dealerUpcards] = Utils.arraySample(
      Array.from(chart.entries()),
    );

    // TODO: Remove this once we have uncommon values defined for all charts.
    if (dealerUpcards.length === 0) {
      return;
    }

    const dealerUpcard = Utils.arraySample(dealerUpcards);
    const [rank1, rank2] = this._playerTotalToTwoCardRank(
      playerTotal,
      chartType,
    );

    this._moveCardsToFront(rank1, rank2, dealerUpcard);
  }

  _setupDeviationsMode(): void {
    const illustrious18DeviationsArray = Array.from(
      illustrious18Deviations.entries(),
    );
    const fab4DeviationsArray = settings.allowLateSurrender
      ? Array.from(fab4Deviations.entries())
      : [];

    const [playerTotal, entries] = Utils.arraySample([
      ...illustrious18DeviationsArray,
      ...fab4DeviationsArray,
    ]);

    const [dealerTotal, deviation] = Utils.arraySample(Array.from(entries));

    this.setupDeviationScenario(playerTotal, dealerTotal, deviation);

    const lt = deviation.index[0][0] === '<';

    // Half time time we randomly alter the running count to something
    // incorrect to be able to test the user's knowledge.
    if (Utils.random(0, 1) === 0) {
      this.hiLoRunningCount += this.decksRemaining * (lt ? 1 : -1);
    }
  }
}

import Card from './card';
import Utils from './utils';
import GameObject from './game-object';
import Shoe from './shoe';
import { Suit, Rank, enumValues } from './types';

export default class Deck extends GameObject {
  entityName = 'deck';

  shoe: Shoe;
  cards: Card[];

  constructor(shoe: Shoe) {
    super();

    this.shoe = shoe;
    this.cards = this.setupCards();
  }

  setupCards(): Card[] {
    const cards: Card[] = [];

    enumValues(Suit).forEach((suit) =>
      enumValues(Rank).forEach((rank) =>
        cards.push(new Card(suit, rank, this.shoe)),
      ),
    );

    Utils.arrayShuffle(cards);

    return cards;
  }
}

import Utils from './utils';
import Game, { settings as gameSettings, GameSettings } from './game';
import Hand from './hand';
import { selectCharts } from './charts/utils';
import {
  ChartType,
  CheckResult,
  Move,
  ChartMove,
  UncommonChart,
  chartMoveToCorrectMove,
  GameStep,
} from './types';

const CHART_MIN_MAX: Record<ChartType, [number, number]> = {
  [ChartType.Hard]: [7, 18],
  [ChartType.Soft]: [13, 20],
  [ChartType.Splits]: [2, 11],
};

function chartMinMax(chartType: ChartType): [number, number] {
  return CHART_MIN_MAX[chartType];
}

type SubCharts = Record<ChartType, ChartMove[][]>;

let cachedSubCharts: SubCharts | undefined;
let cachedCacheKey: string | undefined;

function chartCacheKey(settings: GameSettings): string {
  return `${settings.deckCount}:${settings.hitSoft17}`;
}

function getSubCharts(settings: GameSettings): SubCharts {
  const key = chartCacheKey(settings);
  if (cachedSubCharts !== undefined && cachedCacheKey === key) {
    return cachedSubCharts;
  }

  const { chart: chartGroup } = selectCharts(settings);
  const hard = chartGroup.get(ChartType.Hard);
  const soft = chartGroup.get(ChartType.Soft);
  const splits = chartGroup.get(ChartType.Splits);

  if (!hard || !soft || !splits) {
    throw new Error('Subchart not found');
  }

  cachedSubCharts = {
    [ChartType.Hard]: hard,
    [ChartType.Soft]: soft,
    [ChartType.Splits]: splits,
  };
  cachedCacheKey = key;

  return cachedSubCharts;
}

export default class BasicStrategyChecker {
  static uncommonHands(settings: GameSettings): UncommonChart {
    return selectCharts(settings).uncommon;
  }

  static suggest(game: Game, hand: Hand): Move {
    if (game.state.step === GameStep.WaitingForInsuranceInput) {
      return Move.NoInsurance;
    }

    const subCharts = getSubCharts(gameSettings);
    const chartType = this._chartType(hand);
    const [chartMin, chartMax] = chartMinMax(chartType);

    const playerTotal = Utils.clamp(
      hand.allowSplit ? hand.cards[0].value : hand.cardTotal,
      chartMin,
      chartMax,
    );

    const chart = subCharts[chartType];

    const dealerHints = chart[playerTotal - chartMin];
    const dealersCard = game.dealer.upcard.value;
    const correctMove = dealerHints[dealersCard - 2];

    if (
      correctMove === ChartMove.DoubleOrHit ||
      correctMove === ChartMove.DoubleOrStand
    ) {
      if (hand.allowDouble) {
        return Move.Double;
      } else {
        return correctMove === ChartMove.DoubleOrHit ? Move.Hit : Move.Stand;
      }
    }

    if (
      correctMove === ChartMove.SplitOrHit ||
      correctMove === ChartMove.SplitOrDouble ||
      correctMove === ChartMove.SplitOrStand
    ) {
      if (gameSettings.allowDoubleAfterSplit) {
        return Move.Split;
      } else {
        switch (correctMove) {
          case ChartMove.SplitOrHit:
            return Move.Hit;
          case ChartMove.SplitOrDouble:
            return Move.Double;
          case ChartMove.SplitOrStand:
            return Move.Stand;
        }
      }
    }

    if (correctMove === ChartMove.SurrenderOrSplit) {
      return hand.allowSurrender ? Move.Surrender : Move.Split;
    }

    if (
      correctMove === ChartMove.SurrenderOrHit ||
      correctMove === ChartMove.SurrenderOrStand
    ) {
      if (hand.allowSurrender) {
        return Move.Surrender;
      } else {
        return correctMove === ChartMove.SurrenderOrHit ? Move.Hit : Move.Stand;
      }
    }

    return chartMoveToCorrectMove(correctMove);
  }

  static check(game: Game, hand: Hand, input: Move): CheckResult {
    const correctMove = this.suggest(game, hand);
    if (correctMove == null) {
      return { result: true, code: null, hint: null };
    }

    let hint;

    // TODO: Add rationale for each hint.
    if (correctMove === Move.NoInsurance && input !== Move.NoInsurance) {
      hint = 'decline insurance';
    }

    if (correctMove === Move.Hit && input !== Move.Hit) {
      hint = 'hit';
    }

    if (correctMove === Move.Stand && input !== Move.Stand) {
      hint = 'stand';
    }

    if (correctMove === Move.Double && input !== Move.Double) {
      hint = 'double';
    }

    if (correctMove === Move.Split && input !== Move.Split) {
      hint = 'split';
    }

    if (correctMove === Move.Surrender && input !== Move.Surrender) {
      hint = 'surrender';
    }

    if (hint === undefined) {
      return { result: true, code: null, hint: null };
    }

    return {
      result: false,
      code: correctMove,
      hint: `Basic strategy: last play should have been ${hint}!`,
    };
  }

  static _chartType(hand: Hand): ChartType {
    if (hand.allowSplit) {
      return ChartType.Splits;
    } else if (hand.isSoft) {
      return ChartType.Soft;
    } else {
      return ChartType.Hard;
    }
  }
}

import { GameSettings } from '../game';
