  HandWinner,
  Move,
  BlackjackPayout,
  PlayerStrategy,
  handWinnerToString,
  playerStrategyToString,
  moveToString,
} from './types';

export default class Player extends GameObject {
  entityName = 'player';

  balance: number;
  blackjackPayout: BlackjackPayout;
  debug: boolean;
  handsCount: number;
  handsMax: number;
  handWinner: Map<string, HandWinner>;
  id: string;
  strategy: PlayerStrategy;

  _hands: Hand[];

  constructor({
    balance = 10000 * 100,
    blackjackPayout = BlackjackPayout.ThreeToTwo,
    debug = false,
    handsMax,
    strategy,
  }: {
    balance?: number;
    blackjackPayout?: BlackjackPayout;
    debug?: boolean;
    handsMax: number;
    strategy: PlayerStrategy;
  }) {
    super();

    this.balance = balance;
    this.blackjackPayout = blackjackPayout;
    this.debug = debug;
    this.handsCount = 0;
    this.handsMax = handsMax;
    this.handWinner = new Map();
    this.id = Utils.randomId();
    this.strategy = strategy;

    // TODO: We need two settings here. One is max resplits allowed and the
    // other is max spots allowed. Assuming max spots allowed is 4 (`handsMax`
    // is how many resplits are allowed).
    this._hands = Array.from({ length: handsMax * 4 }, () => {
      // TODO: Use `chainEmitChange`.
      const hand = new Hand(this);
      hand.on(Event.Change, () => this.emitChange());
      return hand;
    });
  }

  getHand(index: number): Hand {
    return this._hands[index];
  }

  eachHand(callback: (hand: Hand) => void): void {
    for (let i = 0; i < this.handsCount; i += 1) {
      callback(this._hands[i]);
    }
  }

  getNPCInput(game: Game, hand: Hand): Move {
    let correctMove: Move;

    if (
      this.strategy === PlayerStrategy.BasicStrategyI18 ||
      this.strategy === PlayerStrategy.BasicStrategyI18Fab4
    ) {
      correctMove =
        HiLoDeviationChecker.suggest(game, hand) ??
        BasicStrategyChecker.suggest(game, hand);
    } else {
      correctMove = BasicStrategyChecker.suggest(game, hand);
    }

    if (this.debug) {
      console.log(
        playerStrategyToString(this.strategy),
        this.id,
        handWinnerToString(HandWinner.Dealer),
        game.dealer.firstHand.serialize(),
        handWinnerToString(HandWinner.Player),
        hand.serialize(),
        `(${hand.cardTotal})`,
        moveToString(correctMove),
      );
    }

    return correctMove;
  }

  addHand(betAmount = 0, cards: Card[] = []): Hand {
    this.handsCount += 1;

    if (this.handsCount > this._hands.length) {
      const hand = new Hand(this);
      hand.on(Event.Change, () => this.emitChange());
      this._hands.push(hand);
    }

    const hand = this._hands[this.handsCount - 1];
    hand.takeCards(cards);

    if (betAmount !== 0) {
      this.useChips(betAmount, { hand });
    }

    this.emitChange();

    return hand;
  }

  takeCard(
    card: Card,
    { hand, prepend = false }: { hand?: Hand; prepend?: boolean } = {},
  ): void {
    const targetHand = hand ?? this._hands[0];
    targetHand.takeCard(card, { prepend });

    if (this.debug) {
      console.log(
        Utils.titleCase(this.entityName),
        this.id,
        'draws card',
        targetHand.serialize({ showHidden: true }),
        `(${targetHand.cardTotal})`,
      );
    }

    this.emitChange();
  }

  removeCards(): void {
    for (let i = 0; i < this.handsCount; i += 1) {
      this._hands[i].removeCards();
    }

    this.handsCount = 0;
  }

  attributes(): PlayerAttributes {
    const handWinner: Record<string, string> = {};

    for (const [key, value] of this.handWinner.entries()) {
      if (typeof value !== 'undefined') {
        handWinner[key] = handWinnerToString(value);
      }
    }

    return {
      id: this.id,
      balance: this.balance,
      hands: this.hands.map((hand) => hand.attributes()),
      handWinner,
    };
  }

  useChips(betAmount: number, { hand }: { hand?: Hand } = {}): void {
    if (!hand) {
      hand = this._hands[0];
    }

    if (hand === undefined) {
      throw new Error(`Player ${this.id} has no hand to add chips to`);
    }

    if (this.balance < betAmount) {
      // TODO: Format cents.
      throw new Error(
        `Insufficient player balance: ${this.balance} < ${betAmount}`,
      );
    }

    hand.betAmount += betAmount;
    this.balance -= betAmount;

    if (this.debug) {
      console.log(
        'Subtracted',
        betAmount,
        'from player',
        this.id,
        'balance:',
        this.balance,
      );
    }
  }

  addChips(betAmount: number): void {
    this.balance += betAmount;

    if (this.debug) {
      console.log('Adding balance', this.id, this.balance, betAmount);
    }
  }

  setHandWinner({
    hand = this._hands[0],
    winner,
    surrender = false,
  }: {
    hand?: Hand;
    winner: HandWinner;
    surrender?: boolean;
  }): void {
    if (this.handWinner.has(hand.id)) {
      return;
    }

    this.handWinner.set(hand.id, winner);

    if (this.debug) {
      console.log(
        'Hand result',
        this.id,
        'winner:',
        winner,
        hand.blackjack ? 'blackjack' : '',
      );
    }

    if (winner === HandWinner.Player) {
      const [ratioNumerator, ratioDenominator] = hand.blackjack
        ? this._blackjackNumeratorDenominator()
        : [1, 1];

      this.addChips(
        hand.betAmount + hand.betAmount * (ratioNumerator / ratioDenominator),
      );
    } else if (winner === HandWinner.Push) {
      this.addChips(hand.betAmount);
    } else if (winner === HandWinner.Dealer && surrender) {
      this.addChips(hand.betAmount / 2);
    }

    this.emit(Event.HandWinner, hand, winner);
    this.emitChange();
  }

  _blackjackNumeratorDenominator(): number[] {
    switch (this.blackjackPayout) {
      case BlackjackPayout.SixToFive:
        return [6, 5];
      case BlackjackPayout.ThreeToTwo:
        return [3, 2];
    }
  }

  get hands(): Hand[] {
    return this._hands.slice(0, this.handsCount);
  }

  get firstHand(): Hand {
    return this._hands[0];
  }

  get isUser(): boolean {
    return this.strategy === PlayerStrategy.UserInput;
  }

  get isNPC(): boolean {
    return !this.isUser;
  }

  // TODO: Consider using `Proxy`.
  get cards(): Card[] {
    return this._hands[0].cards;
  }

  // TODO: Consider using `Proxy`.
  get busted(): boolean {
    return this._hands[0].busted;
  }

  // TODO: Consider using `Proxy`.
  get blackjack(): boolean {
    return this._hands[0].blackjack;
  }

  // TODO: Consider using `Proxy`.
  get cardTotal(): number {
    return this._hands[0].cardTotal;
  }

  // TODO: Consider using `Proxy`.
  get hasPairs(): boolean {
    return this._hands[0].hasPairs;
  }

  // TODO: Consider using `Proxy`.
  get isSoft(): boolean {
    return this._hands[0].isSoft;
  }

  // TODO: Consider using `Proxy`.
  get isHard(): boolean {
    return this._hands[0].isHard;
  }
}

import { settings } from './game';
import GameObject from './game-object';
import { Event } from './event-emitter';
import Utils from './utils';
import Player from './player';
import Card, { CardAttributes } from './card';
import { Rank, rankToString } from './types';
import EventEmitter from './event-emitter';

export type HandAttributes = {
  id: string;
  cards: CardAttributes[];
  hasPairs: boolean;
  cardTotal: number;
  blackjack: boolean;
  firstMove: boolean;
};

export default class Hand extends GameObject {
  static entity = 'hand';

  acesCount!: number;
  betAmount!: number;
  cardHighTotal!: number;
  cardLowTotal!: number;
  cards!: Card[];
  splitCount: number;
  id: string;
  player: Player;

  constructor(player: Player, cards: Card[] = []) {
    super();

    this.reset();

    this.id = Utils.randomId();
    this.player = player;
    this.splitCount = 0;

    for (const card of cards) {
      this.takeCard(card);
    }
  }

  reset(): void {
    this.acesCount = 0;
    this.betAmount = 0;
    this.cardHighTotal = 0;
    this.cardLowTotal = 0;
    this.cards = [];
    this.splitCount = 0;
  }

  takeCards(cards: Card[]): void {
    this.cards = cards;

    for (const card of cards) {
      if (card.showingFace) {
        this.incrementTotalsForCard(card);
      }
    }

    this.emitChange();
  }

  takeCard(card: Card, { prepend = false } = {}): void {
    card.on(Event.Change, this.emitChange);

    if (prepend) {
      this.cards.unshift(card);
    } else {
      this.cards.push(card);
    }

    if (card.showingFace) {
      this.incrementTotalsForCard(card);
    }

    this.emitChange();
  }

  removeCard(): Card {
    const card = this.cards.pop();

    if (!card) {
      throw new Error('No cards left!');
    }

    this.decrementTotalsForCard(card);

    return card;
  }

  incrementTotalsForCard(card: Card): void {
    if (card.rank === Rank.Ace) {
      this.acesCount += 1;
      this.cardLowTotal += 1;

      if (this.cardHighTotal + 11 <= 21) {
        this.cardHighTotal += 11;
      } else {
        this.cardHighTotal += 1;
      }
    } else {
      this.cardHighTotal += card.value;
      this.cardLowTotal += card.value;
    }
  }

  decrementTotalsForCard(card: Card): void {
    if (card.rank === Rank.Ace) {
      this.acesCount -= 1;
      this.cardLowTotal -= 1;

      if (this.acesCount > 0 && this.cardHighTotal + 11 > 21) {
        this.cardHighTotal -= 1;
      } else {
        this.cardHighTotal -= 11;
      }
    } else {
      this.cardHighTotal -= card.value;
      this.cardLowTotal -= card.value;
    }
  }

  removeCards(): Card[] {
    const cards = this.cards;

    if (!EventEmitter.disableEvents) {
      for (const card of cards) {
        card.removeListener(Event.Change, this.emitChange);
      }
    }

    this.reset();
    this.emitChange();

    return cards;
  }

  serialize({ showHidden = false } = {}): string {
    return this.cards
      .map((card) =>
        card.showingFace || showHidden ? rankToString(card.rank) : '?',
      )
      .join(' ');
  }

  attributes(): HandAttributes {
    return {
      id: this.id,
      cards: this.cards.map((card) => card.attributes()),
      hasPairs: this.hasPairs,
      cardTotal: this.cardTotal,
      blackjack: this.blackjack,
      firstMove: this.firstMove,
    };
  }

  get allowSplit(): boolean {
    if (!this.hasPairs || this.splitCount >= settings.maxHandsAllowed - 1) {
      return false;
    }

    if (this.hasAces && this.fromSplit && !settings.allowResplitAces) {
      return false;
    }

    return true;
  }

  get fromSplit(): boolean {
    return this.splitCount > 0;
  }

  get fromAceSplit(): boolean {
    return this.fromSplit && this.cards[0].rank === Rank.Ace;
  }

  get allowSurrender(): boolean {
    return this.firstMove && settings.allowLateSurrender;
  }

  get allowDouble(): boolean {
    return this.firstMove;
  }

  get cardTotal(): number {
    return this.cardHighTotal > 21 ? this.cardLowTotal : this.cardHighTotal;
  }

  get firstMove(): boolean {
    return this.cards.length <= 2;
  }

  get busted(): boolean {
    return this.cardTotal > 21;
  }

  get blackjack(): boolean {
    return (
      this.cards.length === 2 && this.cardHighTotal === 21 && !this.fromSplit
    );
  }

  get finished(): boolean {
    return (
      this.busted || this.blackjack || (this.fromAceSplit && !this.hasAces)
    );
  }

  get hasPairs(): boolean {
    return (
      this.cards.length === 2 && this.cards[0].value === this.cards[1].value
    );
  }

  // A hand is "soft" if there is an ace and the next card will not bust:
  // 1. there's at least one ace
  // 2. counting the aces as value 1, the total is <= 11
  get isSoft(): boolean {
    return this.acesCount > 0 && this.cardLowTotal <= 11;
  }

  get isHard(): boolean {
    return !this.isSoft;
  }

  get hasAces(): boolean {
    return (
      this.cards.length === 2 &&
      this.cards[0].rank === Rank.Ace &&
      this.cards[1].rank === Rank.Ace
    );
  }
}

import { Event } from './event-emitter';
import Hand, { HandAttributes } from './hand';
import { CardAttributes } from './card';
import { HandWinner } from './types';

// Attributes returned by each GameObject subclass.
export type PlayerAttributes = {
  id: string;
  balance: number;
  hands: HandAttributes[];
  handWinner: { [id: string]: string };
};

export type ShoeAttributes = {
  cards: CardAttributes[];
  hiLoRunningCount: number;
  hiLoTrueCount: number;
  penetration: number;
};

// Union of all possible values emitted with Event.Change.
export type ChangeValue =
  | PlayerAttributes
  | HandAttributes
  | CardAttributes
  | ShoeAttributes
  | string
  | number;

// Type guard for narrowing ChangeValue to PlayerAttributes.
export function isPlayerAttributes(
  value: ChangeValue,
): value is PlayerAttributes {
  return (
    typeof value === 'object' &&
    value !== null &&
    'hands' in value &&
    'handWinner' in value
  );
}

// Type guard for objects with an attributes() method (e.g. GameObject subclasses).
function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

export function hasAttributes(
  value: unknown,
): value is { attributes: () => ChangeValue } {
  return (
    isRecord(value) &&
    'attributes' in value &&
    typeof value.attributes === 'function'
  );
}

// Maps each Event enum member to its argument tuple.
export type EventMap = {
  [Event.Change]: [string, ChangeValue];
  [Event.HandWinner]: [Hand, HandWinner];
  [Event.CreateRecord]: [string, Record<string, unknown>];
  [Event.Shuffle]: [];
  [Event.ResetState]: [];
};

import { expect } from 'chai';

import Game from '../../src/game';
import CLIRenderer from '../../src/cli-renderer';
import Card from '../../src/card';
import { Suit, Rank, GameStep, Move, HandWinner } from '../../src/types';

function setupPushGame() {
  const game = new Game({
    debug: process.env.DEBUG != null && process.env.DEBUG !== '',
    playerTablePosition: 1,
    playerCount: 1,
  });

  const length = game.shoe.cards.length;
  const setCard = (index: number, rank: Rank): void => {
    game.shoe.cards[length - index - 1] = new Card(
      Suit.Hearts,
      rank,
      game.shoe,
    );
  };

  // Set up a scenario where both player and dealer have 20 (push).
  // Deal order: player card 1, dealer upcard, player card 2, dealer hole card.
  setCard(0, Rank.Ten); // Player first card: Ten (10)
  setCard(1, Rank.King); // Dealer upcard: King (10)
  setCard(2, Rank.Queen); // Player second card: Queen (10)
  setCard(3, Rank.Jack); // Dealer hole card: Jack (10)

  return game;
}

describe('CLIRenderer', function () {
  describe('#_questionLine()', function () {
    context('when the hand result is a push', function () {
      let renderer: CLIRenderer;
      let game: Game;

      before(function () {
        game = setupPushGame();
        game.betAmount = 10 * 100;

        // Override _setupCliInput and _renderLine since we are in a test
        // environment without a TTY.
        CLIRenderer.prototype._setupCliInput = function () {
          // no-op
        };
        CLIRenderer.prototype._renderLines = function () {
          // no-op
        };

        renderer = new CLIRenderer(game);

        // Step through the game: deal cards.
        game.step();

        // Play right-side NPCs (none in single player).
        game.step();

        // Player stands with 20.
        game.step(Move.Stand);

        // Play left-side NPCs and dealer. Dealer also has 20, so it's a push.
        game.step();

        // Now the game should be in WaitingForNewGameInput.
        expect(game.state.step).to.equal(GameStep.WaitingForNewGameInput);
        expect(game.player.handWinner.values().next().value).to.equal(
          HandWinner.Push,
        );
      });

      it('should return a string containing "Push" not a number', function () {
        const questionLine = renderer._questionLine();

        // The bug: HandWinner.Push is a numeric enum value (2), so the old
        // code returned the number 2 instead of the string "Push".
        expect(questionLine).to.be.a('string');
        expect(questionLine).to.include('Push');
        expect(questionLine).not.to.match(/\b2\b/);
      });

      it('should include "Push" in the outputLines', function () {
        const lines = renderer.outputLines;

        // The question line is the last element.
        const questionLine = lines[lines.length - 1];
        expect(questionLine).to.be.a('string');
        expect(questionLine).to.include('Push');
      });
    });
  });
});

import * as readline from 'readline';

import Renderer from './renderer';
import Game, { settings as gameSettings } from './game';
import Player from './player';
import Hand from './hand';
import { HandWinner, GameStep, handWinnerToString } from './types';

const PLAY_CORRECTION_VISIBLE_TIME_MS = 4000;

// Renders the game state to the terminal.
export default class CLIRenderer implements Renderer {
  game: Game;

  constructor(game: Game) {
    this.game = game;

    this._setupCliInput();

    // Creates space for further output during rendering.
    console.log();
    console.log();
    console.log();
  }

  get outputLines(): string[] {
    return [
      this._playerLine(this.game.dealer, HandWinner.Dealer),
      this._playerLine(this.game.player, HandWinner.Player),
      this._statsLine(),
      this._questionLine(),
    ];
  }

  render(): void {
    const lines = this.outputLines;

    if (this.game.state.playCorrection) {
      lines[2] = this.game.state.playCorrection;

      setTimeout(() => {
        this._renderLines(this.outputLines);
      }, PLAY_CORRECTION_VISIBLE_TIME_MS);
    }

    this._renderLines(lines);
  }

  _renderLines(lines: string[]): void {
    lines.forEach((line, i) => {
      this._renderLine(line, lines.length - i - 1);
    });
  }

  _setupCliInput(): void {
    // Allows collecting keypress events in `getPlayerMoveInput`.
    readline.emitKeypressEvents(process.stdin);

    if (process.stdin.isTTY) {
      process.stdin.setRawMode(true);
    }
  }

  _playerLine(player: Player, type: HandWinner): string {
    const line = player.hands
      .map((hand) => {
        const padding = hand.cardTotal < 10 ? ' ' : '';
        const handFocus = this.game.focusedHand === hand ? '>' : ' ';

        return `${handFocus} (total ${
          hand.cardTotal
        }): ${padding}${this._colorizeHand(hand.serialize())}`;
      })
      .join('   ');

    return `${handWinnerToString(type)} ${line}`;
  }

  _statsLine(): string {
    return `TC: ${this.game.shoe.hiLoTrueCount.toFixed(2)}`;
  }

  _questionLine(): string {
    if (this.game.state.step == null) {
      return '';
    }

    let question;

    if (this.game.state.step === GameStep.WaitingForPlayInput) {
      const choices = ['H (hit)', 'S (stand)'];

      if (this.game.focusedHand.firstMove) {
        choices.push('D (double)');

        if (gameSettings.allowLateSurrender) {
          choices.push('R (surrender)');
        }
      }

      if (this.game.focusedHand.allowSplit) {
        choices.push('P (split)');
      }

      question = choices.join(', ') + '? ';
    } else if (this.game.state.step === GameStep.WaitingForInsuranceInput) {
      question = 'Y (buy insurance), N (no insurance)? ';
    } else if (this.game.state.step === GameStep.WaitingForNewGameInput) {
      const getGameResult = (hand: Hand) => {
        switch (this.game.player.handWinner.get(hand.id)) {
          case HandWinner.Player: {
            const blackjack =
              hand.blackjack && !this.game.dealer.blackjack
                ? 'Blackjack! '
                : '';
            return `${blackjack}Player wins`;
          }
          case HandWinner.Dealer: {
            const blackjack = this.game.dealer.blackjack ? ' (blackjack)' : '';
            return `Dealer wins${blackjack}`;
          }
          case HandWinner.Push:
            return 'Push';
        }
      };

      // TODO: Align these results with the hands above.
      const result = this.game.player.hands
        .map((hand) => getGameResult(hand))
        .join(', ');

      question = `${result} (press any key for next hand)`;
    }

    return question ?? '';
  }

  _renderLine(text: string, yPosBottom = 0): void {
    if (text == null) {
      return;
    }

    readline.cursorTo(process.stdout, 0, process.stdout.rows - yPosBottom - 1);
    readline.clearLine(process.stdout, 0);

    process.stdout.write(text);
  }

  // Alters the text with ANSI escape codes. For example, bold ace cards.
  _colorizeHand(serializedHand: string): string {
    const boldEscape = '\u001b[1m';
    const resetEscape = '\u001b[0m';

    return serializedHand.replace(/A/g, `${boldEscape}A${resetEscape}`);
  }
}

import { expect } from 'chai';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

import FileStorage from '../../src/file-storage';

describe('FileStorage', function () {
  let tempDir: string;
  let storage: FileStorage;

  beforeEach(function () {
    tempDir = fs.mkdtempSync(path.join(os.tmpdir(), 'blackjack-test-'));
    storage = new FileStorage(tempDir);
  });

  afterEach(function () {
    fs.rmSync(tempDir, { recursive: true, force: true });
  });

  describe('#createRecord()', function () {
    it('should write a record file to the database directory', function () {
      const data = { result: 'win', amount: '100' };
      storage.createRecord('test-record', data);

